const fs = require('fs');
const https = require('https');
const querystring = require('querystring');

// A valid 10x10 JPEG white square base64 encoded
const tinyJpegB64 = "";

const postData = querystring.stringify({
  image: tinyJpegB64,
  rectangle: JSON.stringify([{left: 1, top: 1, width: 2, height: 2}])
});

const options = {
  hostname: 'aip.baidubce.com',
  path: '/rest/2.0/image-process/v1/inpainting?access_token=24.cb37983cc5945960c078ba5f897666e1.2592000.1777791691.282335-122715817', // user's current token
  method: 'POST',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
    'Content-Length': Buffer.byteLength(postData)
  }
};

const req = https.request(options, (res) => {
  res.setEncoding('utf8');
  res.on('data', (chunk) => {
    console.log(`BODY: ${chunk}`);
  });
});

req.on('error', (e) => {
  console.error(`problem with request: ${e.message}`);
});

req.write(postData);
req.end();
